-- Migración para crear la tabla de catálogo del programa anual
CREATE TABLE IF NOT EXISTS public.programa_anual_catalogo (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    descripcion TEXT NOT NULL UNIQUE,
    marco_legal TEXT NOT NULL,
    jurisdiccion VARCHAR(100) NOT NULL,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL
);

-- Habilitar RLS
ALTER TABLE public.programa_anual_catalogo ENABLE ROW LEVEL SECURITY;

-- Política de lectura pública
CREATE POLICY "Permitir lectura publica de programa_anual_catalogo" ON public.programa_anual_catalogo
    FOR SELECT TO public USING (true);

